mapper.select:
	/* com.erns.coching.terms.mapper.TermsDAO.getList */

	SELECT B.* FROM (
		SELECT A.*,ROW_NUMBER() OVER () AS RN, COUNT(*) OVER() TOTAL FROM (
			SELECT

				, (SELECT COUNT(*) FROM T_TERMS_INF WHERE TERMS_CD = AA.TERMS_CD) AS CNT
			FROM T_TERMS_INF AA




				ORDER BY AA.RGT_DTTM DESC

		) A
	) B

     WHERE RN BETWEEN (#{offset} + 1) AND #{offset} + #{rowSize}

/* com.erns.coching.terms.mapper.TermsDAO.load */

SELECT

	, (SELECT COUNT(*) FROM T_TERMS_INF WHERE TERMS_CD = AA.TERMS_CD) AS CNT
FROM T_TERMS_INF AA

	AND	AA.TERMS_CD = #{termsCd, jdbcType=VARCHAR}
	AND AA.USE_YN 	= 'Y'

mapper.insert:
/* com.erns.coching.terms.mapper.TermsDAO.insert */

INSERT INTO T_TERMS_INF (
	  TERMS_CD
	, VERSION
	, TERMS_TYPE
	, CONTENT
	, USE_YN
	, REQUIRED_YN
	, FROM_DATE
	, TO_DATE
	, REMARKS

	, RGTR
	, RGT_DTTM
	, CHNR
	, CHNG_DTTM
) VALUES (
	  #{termsCd		, jdbcType=VARCHAR}
	, #{version		, jdbcType=VARCHAR}
	, #{termsType	, jdbcType=VARCHAR}
	, #{content		, jdbcType=VARCHAR}
	, #{useYn		, jdbcType=CHAR}
	, COALESCE(#{requiredYn	, jdbcType=CHAR}, 'N')
	, #{fromDate	, jdbcType=VARCHAR}
	, #{toDate		, jdbcType=VARCHAR}
	, #{remarks		, jdbcType=VARCHAR}

	, #{rgtr		, jdbcType=INTEGER}
	, now()
	, #{chnr		, jdbcType=INTEGER}
	, now()
)

mapper.update:
/* com.erns.coching.terms.mapper.TermsDAO.update */

UPDATE T_TERMS_INF SET
	  TERMS_TYPE    = #{termsType	, jdbcType=VARCHAR}
	, CONTENT       = #{content		, jdbcType=VARCHAR}
	, REQUIRED_YN   = #{requiredYn	, jdbcType=CHAR}
	, FROM_DATE   	= #{fromDate	, jdbcType=VARCHAR}
	, TO_DATE   	= #{toDate		, jdbcType=VARCHAR}
	, REMARKS   	= #{remarks		, jdbcType=VARCHAR}

	, CHNR          = #{chnr		, jdbcType=INTEGER}
	, CHNG_DTTM     = now()

	AND	TERMS_CD = #{termsCd	, jdbcType=VARCHAR}
	AND VERSION  = #{version	, jdbcType=VARCHAR}

/* com.erns.coching.terms.mapper.TermsDAO.updateUseYn */
UPDATE T_TERMS_INF SET USE_YN = CASE WHEN VERSION = #{version, jdbcType=VARCHAR} THEN 'Y' ELSE 'N' END
AND TERMS_CD = #{termsCd, jdbcType=VARCHAR}

mapper.select:
/* com.erns.coching.terms.mapper.TermsDAO.getVersionList */

SELECT VERSION
FROM T_TERMS_INF

	TERMS_CD = #{termsCd, jdbcType=VARCHAR}

ORDER BY RGT_DTTM DESC
